export function getAllArticles(): Article[] {
  return mockArticles;
}

export function getArticleBySlug(slug: string): Article | undefined {
  return mockArticles.find((a) => a.slug === slug);
}

export function getArticlesByCategory(category: string): Article[] {
  if (category === "All") return mockArticles;
  return mockArticles.filter((a) => a.category === category);
}

export function getFeaturedArticles(): Article[] {
  return mockArticles.filter((a) => a.isFeatured);
}

export function getRelatedArticles(slug: string, limit = 3): Article[] {
  const article = getArticleBySlug(slug);
  if (!article) return mockArticles.slice(0, limit);
  return mockArticles
    .filter(
      (a) =>
        a.slug !== slug &&
        (a.category === article.category ||
          a.tags.some((t) => article.tags.includes(t)))
    )
    .slice(0, limit);
}

